"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import ProtectedRoute from "../components/ProtectedRoute";
import { useAuth } from "../context/AuthContext";

export default function DashboardPage() {
    const [subpages, setSubpages] = useState<any[]>([]);
    const [error, setError] = useState<string | null>(null);
    const { access } = useAuth(); // Get access array from AuthContext

    useEffect(() => {
        const fetchSubpages = async () => {
            try {
                const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/subpages`, {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify(access), // Send access array to backend
                });
                if (!response.ok) {
                    throw new Error("Failed to fetch subpages");
                }
                const data = await response.json();
                setSubpages(data);
            } catch (err) {
                setError(err instanceof Error ? err.message : "An unknown error occurred");
            }
        };

        if (access.length > 0) {
            fetchSubpages();
        }
    }, [access]);

    if (error) {
        return (
            <ProtectedRoute>
                <div className="min-h-screen bg-black text-gray-200 p-6 flex items-center justify-center">
                    <p className="text-red-500">Error: {error}</p>
                </div>
            </ProtectedRoute>
        );
    }

    if (subpages.length === 0) {
        return (
            <ProtectedRoute>
                <div className="min-h-screen bg-black text-gray-200 p-6 flex items-center justify-center">
                    <p className="text-lg text-gray-400">No subpages available.</p>
                </div>
            </ProtectedRoute>
        );
    }

    return (
        <ProtectedRoute>
            <div className="min-h-screen bg-black text-gray-200 p-6">
                <h1 className="text-3xl font-bold mb-6">Dashboard</h1>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {subpages.map((subpage) => {
                        const hasAccess = access.includes(subpage.nick); // Check if user has access to this subpage
                        return (
                            <div
                                key={subpage.nick}
                                className={`block bg-gray-800 p-4 rounded-lg shadow ${
                                    hasAccess ? "hover:bg-gray-700" : "opacity-50"
                                } transition duration-200`}
                            >
                                {hasAccess ? (
                                    <Link href={subpage.link}>
                                        <h2 className="text-xl font-bold">{subpage.name}</h2>
                                        <p className="text-gray-400">{subpage.nick}</p>
                                    </Link>
                                ) : (
                                    <div>
                                        <h2 className="text-xl font-bold">{subpage.name}</h2>
                                        <p className="text-gray-400">{subpage.nick}</p>
                                        <p className="text-red-500 text-sm">Access Restricted</p>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>
        </ProtectedRoute>
    );
}
